query:
-- Compass Assurance (C0065) - NBN EE Fibre 500mb - find matching service
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C0065' ORDER BY monthlyCost DESC;

-- Auriga Group (C0020) - AAPT Fibre 400 - find matching service
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId IN ('C0020', 'C2416') ORDER BY monthlyCost DESC;

-- Lead Education (C0135) - FIBRE400/36 - find matching service
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId IN ('C0135', 'C2431') ORDER BY monthlyCost DESC;

-- Nu-Dev (C0176) - TPG Fibre 400 - find matching service
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId = 'C0176' ORDER BY monthlyCost DESC;

-- Strata Dynamics (C0231) - 400/400 Fibre + Teams Voice SIP - find matching services
SELECT externalId, planName, provider, monthlyCost, monthlyRevenue FROM services
WHERE customerExternalId IN ('C0231', 'C2447') ORDER BY monthlyCost DESC;

